outbound.set-body:
@{
        var src = context.Response.Body.As(preserveContent: true);

        var result = new JObject();
        result["clienteId"] = (string)src["id"];
        result["nombre"] = (string)src["fullName"];
        result["correo"] = (string)src["contact"]?["email"];
        result["estado"] = (string)src["status"];

        return result.ToString();
    }
